// ========================================
// SHARED CONSTANTS
// ========================================
// Common constants used across all healing rotations

// Power types
private const int MANA = 0;

// Item IDs
private const int HEALTHSTONE_ID = 5512;

// Timing
private const int DIAGNOSTIC_LOG_INTERVAL_MS = 2000;

// ========================================
// SHARED INITIALIZATION
// ========================================
// Common macros and functions used across all healing rotations

// Initializes focus macros for party and raid targeting
private void InitializeFocusMacros()
{
    Macros.Add("focus_player", "/focus player");

    // Party focus macros (party1-4)
    for (int i = 1; i <= 4; i++)
    {
        Macros.Add("focus_party" + i, "/focus party" + i);
    }

    // Raid focus macros (raid1-28, supports up to 28 raid members)
    for (int i = 1; i <= 28; i++)
    {
        Macros.Add("focus_raid" + i, "/focus raid" + i);
    }
}

// Initializes common utility macros
private void InitializeUtilityMacros()
{
    Macros.Add("target_enemy", "/targetenemy");
    Macros.Add("use_healthstone", "/use Healthstone");
}

// Initializes the Healthstone check custom function
private void InitializeHealthstoneFunction()
{
    string hasHealthstoneCode = "return GetItemCount(5512) > 0 and 1 or 0";
    CustomFunctions.Add("HasHealthstone", hasHealthstoneCode);
}

// Initializes all shared components (call this in class-specific Initialize)
private void InitializeSharedComponents()
{
    InitializeFocusMacros();
    InitializeUtilityMacros();
    InitializeHealthstoneFunction();
}

// ========================================
// SHARED MAIN TICK LOGIC
// ========================================
// Common tick loop structure for all healing rotations

public override bool CombatTick()
{
    // Skip if player is dead
    if (Inferno.IsDead("player")) return true;

    // Wait for GCD to finish
    if (Inferno.GCD() != 0) return true;

    // Process queued action first (two-tick casting pattern)
    if (ProcessQueue()) return true;

    // Periodic diagnostic logging
    if (ThrottleIsOpen("diag", DIAGNOSTIC_LOG_INTERVAL_MS))
    {
        ThrottleRestart("diag");
        List<string> gm = GetGroupMembers();
        string info = "";
        for (int i = 0; i < gm.Count; i++) 
            info += gm[i] + "=" + HealthPct(gm[i]) + "% ";
        Log("Tick: combat=" + Inferno.InCombat("player") + " group=" + gm.Count + " | " + info);
    }

    // Execute rotation priorities
    int mapId = Inferno.GetMapID();
    if (RunDungeonGambits(mapId)) return true;
    if (RunHealGambits()) return true;
    if (RunDmgGambits()) return true;

    // Always return true to keep ticking
    return true;
}

// Use combat tick logic for out-of-combat as well
public override bool OutOfCombatTick() 
{ 
    return CombatTick(); 
}

// Cleanup when rotation stops
public override void OnStop() 
{ 
    Log("Rotation stopped"); 
}
